import React, { useContext, useEffect, useState } from "react";
import NewCommentForm from "../Components/Forms/NewCommentForm";
import CommentsList from "../Components/CommentsList";
import PostUpdateForm from "../Components/Forms/PostUpdateForm";
import Loading from "../Components/Loading";
import { deletePost, getPostById, updatePost, incrementPostViews, likePost, togglePublishPost } from "../lib/api";
import { useNavigate, useParams, Link } from "react-router-dom";
import Banner from "../Components/Banner";
import AuthContext from "../store/auth-context";
import { useTranslation } from "react-i18next";
import ScrollToTop from "../Components/ScrollToTop";

function readTime(content = "") {
  return Math.max(1, Math.ceil(content.trim().split(/\s+/).length / 200));
}

const EyeIcon = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>
  </svg>
);

const HeartIcon = ({ filled }) => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill={filled ? "currentColor" : "none"}
    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
  </svg>
);

const PostPage = () => {
  const [post, setPost]                   = useState({});
  const [comments, setComments]           = useState([]);
  const [isLoading, setIsLoading]         = useState(true);
  const [isPostUpdated, setIsPostUpdated] = useState(false);
  const [isPostDeleted, setIsPostDeleted] = useState(false);
  const [isDeletingPost, setIsDeletingPost] = useState(false);
  const [error, setError]                 = useState(null);
  const [liked, setLiked]                 = useState(false);
  const [likeCount, setLikeCount]         = useState(0);
  const [views, setViews]                 = useState(0);
  const [isTogglingPublish, setIsTogglingPublish] = useState(false);

  const { id }     = useParams();
  const authCtx    = useContext(AuthContext);
  const navigate   = useNavigate();
  const { t }      = useTranslation();

  /* check if user already liked this post (persisted in localStorage) */
  useEffect(() => {
    const liked = localStorage.getItem(`inkwell-liked-${id}`);
    if (liked) setLiked(true);
  }, [id]);

  const onPostUpdate = (updatedContent, formikHelpers) => {
    setTimeout(() => {
      updatePost({ id: post.id, content: updatedContent.content }, authCtx.token)
        .then(() => setIsPostUpdated(true))
        .catch(console.log)
        .finally(() => formikHelpers.setSubmitting(false));
    }, 1000);
  };

  const onPostDelete = () => {
    setIsDeletingPost(true);
    setTimeout(() => {
      deletePost(post.id, authCtx.token)
        .then(() => setIsPostDeleted(true))
        .catch(console.log)
        .finally(() => setIsDeletingPost(false));
    }, 1000);
  };

  const onLike = () => {
    if (liked) return;
    likePost(post.id).then(updated => {
      setLikeCount(updated.likeCount);
      setLiked(true);
      localStorage.setItem(`inkwell-liked-${id}`, "1");
    }).catch(console.log);
  };

  const onTogglePublish = () => {
    setIsTogglingPublish(true);
    const newPublished = !post.published;
    togglePublishPost(post.id, newPublished, authCtx.token)
      .then(updated => {
        setPost(prev => ({ ...prev, published: updated.published }));
      })
      .catch(console.log)
      .finally(() => setIsTogglingPublish(false));
  };

  const fetchPostById = () => {
    setIsLoading(true);
    getPostById(id)
      .then(p => {
        setPost(p);
        setComments(p.comments);
        setLikeCount(p.likeCount || 0);
        setViews(p.views || 0);
      })
      .catch(e => setError(e.message))
      .finally(() => setIsLoading(false));
  };

  /* increment view counter once on mount */
  useEffect(() => {
    incrementPostViews(id);
  }, [id]);

  useEffect(() => {
    setTimeout(() => {
      if (isPostUpdated) { setIsPostUpdated(false); fetchPostById(); }
      if (isPostDeleted) { setIsPostDeleted(false); navigate("/"); }
    }, 1000);
  }, [isPostUpdated, isPostDeleted]);

  useEffect(() => { setTimeout(fetchPostById, 1000); }, []);

  const canEdit = authCtx.isLoggedIn &&
    (authCtx.userName === post.blogUser || authCtx.authorities === authCtx.ROLES.admin);

  return (
    <div className="ink-post-page page-fade-in">
      <div className="ink-post-shell">
        <Link to="/" className="ink-back-btn">← All Posts</Link>

        {isLoading && <Loading />}
        {error && <Banner className="text-danger border-danger" message={error} />}

        {!isLoading && !error && (
          <>
            {/* meta pills row */}
            <div style={{ marginBottom: "0.75rem", display: "flex", gap: "0.5rem", alignItems: "center", flexWrap: "wrap" }}>
              <span className="ink-date-pill">
                {readTime(post.content)} min read
              </span>
              <span className="ink-date-pill">
                {comments.length} comment{comments.length !== 1 ? "s" : ""}
              </span>
              <span className="ink-date-pill ink-views-pill">
                <EyeIcon /> {views} view{views !== 1 ? "s" : ""}
              </span>
              {!post.published && (
                <span className="ink-draft-badge">Draft</span>
              )}
            </div>

            <PostUpdateForm
              onSubmit={onPostUpdate}
              onPostDelete={onPostDelete}
              isDeletingPost={isDeletingPost}
              isPostDeleted={isPostDeleted}
              post={post}
            />

            {/* like + publish row */}
            <div className="ink-post-reactions">
              <button
                className={`ink-like-btn${liked ? " liked" : ""}`}
                onClick={onLike}
                disabled={liked}
                title={liked ? "You liked this post" : "Like this post"}
              >
                <HeartIcon filled={liked} />
                <span>{likeCount}</span>
              </button>

              {canEdit && (
                <button
                  className={`ink-publish-toggle-btn${post.published ? " published" : ""}`}
                  onClick={onTogglePublish}
                  disabled={isTogglingPublish}
                >
                  {isTogglingPublish
                    ? "Saving…"
                    : post.published
                      ? "✓ Published — click to unpublish"
                      : "○ Draft — click to publish"
                  }
                </button>
              )}
            </div>

            {isPostUpdated && (
              <Banner className="text-success border-success mt-4"
                message={`${t("updatedBy", { type: "post" })} ${authCtx.userName}`} />
            )}
            {isPostDeleted && (
              <Banner className="text-danger border-danger mt-4"
                message={`${t("deleteBy", { type: "post" })} ${authCtx.userName}`} />
            )}

            <hr className="ink-divider" />

            {(authCtx.isLoggedIn || comments.length > 0) && (
              <div className="ink-comments-header">
                <h2 className="ink-comments-title">{t("comments")}</h2>
                <span className="ink-comments-badge">{comments.length}</span>
              </div>
            )}

            {authCtx.isLoggedIn && (
              <NewCommentForm onContentChange={fetchPostById} postId={post.id} />
            )}

            <CommentsList onContentChange={fetchPostById} comments={comments} />
          </>
        )}
      </div>
      <ScrollToTop />
    </div>
  );
};

export default PostPage;
